module top_module (
    input v,
    input w,
    input x,
    input m,
    output reg obf_f
);
    always @(*) begin
        case ({v, w, x, m})
            4'b1101: obf_f = 1'b1;
            4'b0100: obf_f = 1'b0;
            4'b0010: obf_f = 1'b0;
            4'b1010: obf_f = 1'b0;
            4'b1100: obf_f = 1'b0;
            4'b0101: obf_f = 1'b1;
            4'b1000: obf_f = 1'b1;
            4'b0000: obf_f = 1'b0;
            4'b1110: obf_f = 1'b0;
            4'b0111: obf_f = 1'b0;
            4'b0001: obf_f = 1'b0;
            4'b1001: obf_f = 1'b1;
            4'b0110: obf_f = 1'b0;
            4'b0011: obf_f = 1'b0;
            4'b1111: obf_f = 1'b0;
            4'b1011: obf_f = 1'b1;
        endcase
    end
endmodule
